import os
p='/tmp/Oma_folio/tools/reaction-diffusion-lab.html'
os.makedirs(os.path.dirname(p),exist_ok=True)
H='''<!DOCTYPE html><html><head><meta charset=utf-8><title>RDL</title><style>*{margin:0;padding:0}body{background:#000;color:#FFA500;font-family:monospace;overflow:hidden}canvas{display:block;cursor:crosshair}#ui{position:fixed;top:8px;right:8px;background:rgba(0,0,0,.85);border:1px solid #FF8C00;border-radius:6px;padding:10px;font-size:11px;max-width:200px;z-index:1}#ui label{display:block;margin:3px 0}#ui input{width:80px;accent-color:#FF8C00}button{background:#1a1a1a;color:#FF8C00;border:1px solid #FF8C00;border-radius:3px;padding:2px 8px;margin:2px;cursor:pointer;font-size:10px}button:hover{background:#FF8C00;color:#000}</style></head><body><canvas id=c></canvas><div id=ui><b>RDL</b><br><label>F:<input id=sF type=range min=.01 max=.1 step=.001 value=.035><span id=vF>.035</span></label><label>K:<input id=sK type=range min=.04 max=.07 step=.001 value=.065><span id=vK>.065</span></label><br><button onclick=setP(.035,.065)>Spots</button><button onclick=setP(.04,.06)>Maze</button><button onclick=setP(.025,.06)>Coral</button><button onclick=setP(.074,.064)>Solitons</button><br><button onclick=reset()>Reset</button><button id=pbtn onclick=togglePause()>Pause</button></div>'''
H+='<script id=vs type=x-shader/x-vertex>#version 300 es\nin vec2 p;void main(){gl_Position=vec4(p,0,1);}</script>'
H+='<script id=fsim type=x-shader/x-fragment>#version 300 es\nprecision highp float;uniform sampler2D S;uniform vec2 R;uniform float Du,Dv,F,K,dt;uniform vec2 M;uniform float Md;out vec4 O;void main(){vec2 uv=gl_FragCoord.xy/R;vec4 c=texture(S,uv);float U=c.r,V=c.g;if(Md>.5){float d=length(gl_FragCoord.xy-M);if(d<5.)V=1.;}float lU=-4.*c.r,lV=-4.*c.g;lU+=texture(S,uv+vec2(1,0)/R).r+texture(S,uv-vec2(1,0)/R).r+texture(S,uv+vec2(0,1)/R).r+texture(S,uv-vec2(0,1)/R).r;lV+=texture(S,uv+vec2(1,0)/R).g+texture(S,uv-vec2(0,1)/R).g+texture(S,uv+vec2(0,1)/R).g+texture(S,uv-vec2(0,1)/R).g;float uvv=U*V*V;U+=dt*(Du*lU-uvv+F*(1.-U));V+=dt*(Dv*lV+uvv-(F+K)*V);O=vec4(clamp(U,0.,1.),clamp(V,0.,1.),0.,1.);}</script>'
H+='<script id=fdsp type=x-shader/x-fragment>#version 300 es\nprecision highp float;uniform sampler2D S;uniform vec2 R;out vec4 O;void main(){vec2 uv=gl_FragCoord.xy/R;vec4 c=texture(S,uv);float V=c.g;float t=smoothstep(0.,.35,V);vec3 col=mix(vec3(.04,.02,.01),vec3(1.,.55,.0),t);col=mix(col,vec3(1.,.85,.3),smoothstep(.5,1.,V));col*=1.-.4*length(uv-.5);O=vec4(col,1.);}</script>'
H+='<script>var gl,pgs,pgd,fbo=[null,null],cur=0,W,H,pau=0,md=0,mx=0,my=0,F=.035,K=.065,Du=1,Dv=.5,dt=1;function cs(s,t){var sh=gl.createShader(t);gl.shaderSource(sh,s);gl.compileShader(sh);return sh}function cp(v,f){var p=gl.createProgram();gl.attachShader(p,cs(v,gl.VERTEX_SHADER));gl.attachShader(p,cs(f,gl.FRAGMENT_SHADER));gl.linkProgram(p);return p}function mkF(){var t=gl.createTexture();gl.bindTexture(gl.TEXTURE_2D,t);gl.texParameteri(gl.TEXTURE_2D,gl.TEXTURE_MIN_FILTER,gl.LINEAR);gl.texParameteri(gl.TEXTURE_2D,gl.TEXTURE_MAG_FILTER,gl.LINEAR);gl.texParameteri(gl.TEXTURE_2D,gl.TEXTURE_WRAP_S,gl.CLAMP_TO_EDGE);gl.texParameteri(gl.TEXTURE_2D,gl.TEXTURE_WRAP_T,gl.CLAMP_TO_EDGE);gl.texImage2D(gl.TEXTURE_2D,0,gl.RGBA16F,W,H,0,gl.RGBA,gl.HALF_FLOAT,null);var f=gl.createFramebuffer();gl.bindFramebuffer(gl.FRAMEBUFFER,f);gl.framebufferTexture2D(gl.FRAMEBUFFER,gl.COLOR_ATTACHMENT0,gl.TEXTURE_2D,t,0);return{t:t,f:f}}function initF(){for(var i=0;i<2;i++){if(fbo[i]){gl.deleteTexture(fbo[i].t);gl.deleteFramebuffer(fbo[i].f)}fbo[i]=mkF()}seed()}function seed(){gl.bindFramebuffer(gl.FRAMEBUFFER,fbo[0].f);gl.clearColor(1,0,0,1);gl.clear(gl.COLOR_BUFFER_BIT);gl.viewport(0,0,W,H);for(var i=0;i<8;i++){var cx=Math.random()*W,cy=Math.random()*H;for(var x=-6;x<=6;x++)for(var y=-6;y<=6;y++)if(x*x+y*y<36)gl.texSubImage2D(gl.TEXTURE_2D,0,cx+x,cy+y,1,1,gl.RGBA,gl.UNSIGNED_BYTE,new Uint8Array([0,0,255,255]))}}function resize(){var c=document.getElementById(c);W=c.width=innerWidth*devicePixelRatio;H=c.height=innerHeight*devicePixelRatio;gl.viewport(0,0,W,H);initF()}window.onload=function(){var c=document.getElementById(c);gl=c.getContext(webgl2);if(!gl){alert(WebGL2 required);return}var vs=document.getElementById(vs).textContent.trim();pgs=cp(vs,document.getElementById(fsim).textContent.trim());pgd=cp(vs,document.getElementById(fdsp).textContent.trim());var b=gl.createBuffer();gl.bindBuffer(gl.ARRAY_BUFFER,b);gl.bufferData(gl.ARRAY_BUFFER,new Float32Array([-1,-1,1,-1,-1,1,1,1]),gl.STATIC_DRAW);function at(p){var l=gl.getAttribLocation(p,p);gl.enableVertexAttribArray(l);gl.vertexAttribPointer(l,2,gl.FLOAT,!1,0,0)}at(pgs);at(pgd);resize();addEventListener(resize,resize);c.addEventListener(mousedown,function(e){md=1;mx=e.clientX*devicePixelRatio;my=(innerHeight-e.clientY)*devicePixelRatio});c.addEventListener(mouseup,function(){md=0});c.addEventListener(mousemove,function(e){mx=e.clientX*devicePixelRatio;my=(innerHeight-e.clientY)*devicePixelRatio});document.getElementById(sF).oninput=function(){F=+this.value;document.getElementById(vF).textContent=F.toFixed(3)};document.getElementById(sK).oninput=function(){K=+this.value;document.getElementById(vK).textContent=K.toFixed(3)};window.setP=function(f,k){F=f;K=k;document.getElementById(sF).value=f;document.getElementById(sK).value=k;document.getElementById(vF).textContent=f.toFixed(3);document.getElementById(vK).textContent=k.toFixed(3)};window.reset=function(){initF()};window.togglePause=function(){pau=!pau;document.getElementById(pbtn).textContent=pau?Play:Pause};function frame(){if(!pau){for(var s=0;s<8;s++){gl.useProgram(pgs);gl.bindFramebuffer(gl.FRAMEBUFFER,fbo[1-cur].f);gl.activeTexture(gl.TEXTURE0);gl.bindTexture(gl.TEXTURE_2D,fbo[cur].t);gl.uniform1i(gl.getUniformLocation(pgs,S),0);gl.uniform2f(gl.getUniformLocation(pgs,R),W,H);gl.uniform1f(gl.getUniformLocation(pgs,F),F);gl.uniform1f(gl.getUniformLocation(pgs,K),K);gl.uniform1f(gl.getUniformLocation(pgs,Du),Du);gl.uniform1f(gl.getUniformLocation(pgs,Dv),Dv);gl.uniform1f(gl.getUniformLocation(pgs,dt),dt);gl.uniform2f(gl.getUniformLocation(pgs,M),mx,my);gl.uniform1f(gl.getUniformLocation(pgs,Md),md);gl.drawArrays(gl.TRIANGLE_STRIP,0,4);cur=1-cur}}gl.useProgram(pgd);gl.bindFramebuffer(gl.FRAMEBUFFER,null);gl.activeTexture(gl.TEXTURE0);gl.bindTexture(gl.TEXTURE_2D,fbo[cur].t);gl.uniform1i(gl.getUniformLocation(pgd,S),0);gl.uniform2f(gl.getUniformLocation(pgd,R),W,H);gl.drawArrays(gl.TRIANGLE_STRIP,0,4);requestAnimationFrame(frame)}frame()};</script></body></html>'
